import Redis from 'ioredis';
import { prisma } from '../lib/prisma';

const redis = new Redis(process.env.REDIS_URL);
const CACHE_TTL = 300; // 5 minutes

async function getPostById(id: number) {
  const cacheKey = `post:${id}`;

  // 1. Check cache first
  const cached = await redis.get(cacheKey);
  if (cached) return JSON.parse(cached);

  // 2. Cache miss -- query the database
  const post = await prisma.post.findUnique({
    where: { id },
    include: { author: { select: { username: true } }, tags: true },
  });

  if (!post) return null;

  // 3. Store in cache for next time
  await redis.set(cacheKey, JSON.stringify(post), 'EX', CACHE_TTL);

  return post;
}

// Invalidate cache when data changes
async function updatePost(id: number, data: UpdatePostInput) {
  const post = await prisma.post.update({ where: { id }, data });

  // Delete cached version so next read gets fresh data
  await redis.del(`post:${id}`);

  return post;
}
